3030	// beadParentChain returns the chain of parent IDs starting at parentID and
3031	// walking upward through stored parent links. The returned chain excludes the
3032	// child bead itself and includes the offending ancestor if one is found.
3033	func beadParentChain(byID map[string]*Bead, parentID string) ([]string, error) {
3034		if parentID == "" {
3035			return nil, nil
3036		}
3037		chain := make([]string, 0, 4)
3038		seen := make(map[string]bool)
3039		current := parentID
3040		for current != "" {
3041			if seen[current] {
3042				chain = append(chain, current)
3043				return chain, fmt.Errorf("bead: parent cycle detected: %s", strings.Join(chain, " -> "))
3044			}
3045			seen[current] = true
3046			chain = append(chain, current)
3047			next, ok := byID[current]
3048			if !ok || next.Parent == "" {
3049				break
3050			}
3051			current = next.Parent
3052		}
3053		return chain, nil
3054	}
